package nativesym

import (
	"encoding/base64"
	"testing"
)

const elfHandleRequestObjectBase64 = ""

func ELFHandleRequestObject(t testing.TB) []byte {
	t.Helper()
	body, err := base64.StdEncoding.DecodeString(elfHandleRequestObjectBase64)
	if err != nil {
		t.Fatalf("decode ELF fixture: %v", err)
	}
	return body
}

func ELFHandleRequestObjectBytes() []byte {
	body, err := base64.StdEncoding.DecodeString(elfHandleRequestObjectBase64)
	if err != nil {
		panic(err)
	}
	return body
}
